from typing import List, Optional
import strawberry
from sqlalchemy.ext.asyncio import AsyncSession
from sqlalchemy.orm import joinedload
from models import Product, Review, Seller, Category, Image

@strawberry.type
class ProductType:
    id: int
    name: str
    price: float
    reviews: List["ReviewType"]
    seller: "SellerType"
    category: "CategoryType"
    images: List["ImageType"]

@strawberry.type
class ReviewType:
    id: int
    product_id: int
