@strawberry.type
class CategoryType:
    id: int
    name: str
    products: List[ProductType]

@strawberry.type
class ImageType:
    id: int
    product_id: int
    url: str

@strawberry.type
class Query:
    @strawberry.field
    async def product(self, id: int, db: AsyncSession) -> Optional[ProductType]:
        product = await db.get(Product, id)
        if product is not None:
            await db.expire(product)
            await db.refresh(
                product,
                join=[Review, Seller, Category, Image],
                load_options=[joinedload(Product.reviews), joinedload(Product.seller), joinedload(Product.category), joinedload(Product.images)],
            )
        return ProductType.from_orm(product) if product else None

    @strawberry.field
    async def products(self, db: AsyncSession) -> List[ProductType]:
        products = await db.scalars(db.select(Product).options(joinedload(Product.reviews), joinedload(Product.seller), joinedload(Product.category), joinedload(Product.images)))
        return [ProductType.from_orm(product) for product in products]

schema = strawberry.Schema(query=Query)